{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://kapow.dev/schemas/technical-contract.schema.json",
  "title": "Technical Contract",
  "description": "Schema for technical contracts that define system-level guarantees: API behavior, search invariants, auth rules, data integrity, and performance bounds.",
  "type": "object",
  "required": ["id", "title", "description", "status", "owner", "category"],
  "additionalProperties": false,
  "properties": {
    "id": {
      "type": "string",
      "pattern": "^[a-z0-9]+(-[a-z0-9]+)*$",
      "description": "Unique identifier in kebab-case (e.g., 'search-validation-parity')."
    },
    "title": {
      "type": "string",
      "minLength": 1,
      "description": "Human-readable name of the contract."
    },
    "description": {
      "type": "string",
      "minLength": 1,
      "description": "What this contract guarantees at the system level."
    },
    "status": {
      "type": "string",
      "enum": ["shipped", "experimental", "planned", "deprecated"],
      "description": "Current lifecycle status."
    },
    "owner": {
      "type": "string",
      "minLength": 1,
      "description": "Team or person responsible for this contract."
    },
    "category": {
      "type": "string",
      "enum": ["api", "search", "auth", "data", "performance", "infrastructure"],
      "description": "Type of technical contract."
    },
    "guarantees": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["description"],
        "additionalProperties": false,
        "properties": {
          "description": {
            "type": "string",
            "description": "What is guaranteed."
          },
          "metric": {
            "type": "string",
            "description": "Measurable metric (e.g., 'p99 latency', 'error rate')."
          },
          "threshold": {
            "type": "string",
            "description": "Acceptable bound (e.g., '< 500ms', '0%', '>= 99.9%')."
          }
        }
      },
      "description": "Specific technical guarantees this contract makes."
    },
    "dependencies": {
      "type": "array",
      "items": {
        "type": "string",
        "pattern": "^[a-z0-9]+(-[a-z0-9]+)*$"
      },
      "description": "IDs of other contracts this one depends on."
    },
    "source_files": {
      "type": "array",
      "items": { "type": "string" },
      "description": "File paths (relative to repo root) that implement this contract."
    },
    "tests": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Test file paths or test name patterns that verify this contract."
    },
    "issues": {
      "type": "array",
      "items": {
        "type": "string",
        "pattern": "^kapow-[a-z0-9]+",
        "description": "Beads issue ID."
      },
      "description": "Linked beads issue IDs."
    },
    "evidence": {
      "type": "object",
      "required": ["type"],
      "additionalProperties": false,
      "properties": {
        "type": {
          "type": "string",
          "enum": ["test", "manual", "monitoring", "assertion"],
          "description": "How the contract claim is verified."
        },
        "description": {
          "type": "string",
          "description": "Details about the verification method."
        },
        "references": {
          "type": "array",
          "items": { "type": "string" },
          "description": "Links to test runs, dashboards, or other proof."
        }
      },
      "description": "How this contract is verified."
    },
    "created": {
      "type": "string",
      "format": "date",
      "description": "Date the contract was created (YYYY-MM-DD)."
    },
    "updated": {
      "type": "string",
      "format": "date",
      "description": "Date the contract was last updated (YYYY-MM-DD)."
    }
  }
}

{
  "id": "search-validation-parity",
  "title": "Search Validation Parity",
  "description": "All three search entry points (GraphQL, CSV export, MCP) apply identical validation rules, producing the same accept/reject decisions for any given request.",
  "status": "shipped",
  "owner": "core",
  "category": "search",
  "guarantees": [
    {
      "description": "Invalid filter names are rejected with the same error message across all entry points."
    },
    {
      "description": "Auth-restricted fields return 'unauthorized' errors for unauthenticated requests across all entry points."
    },
    {
      "description": "Pagination bounds (limit 1-1000) are enforced identically across all entry points."
    },
    {
      "description": "Geographic radius constraints (1-500 miles) are enforced identically across all entry points."
    }
  ],
  "dependencies": [],
  "source_files": [
    "api/internal/search/validate.go",
    "api/internal/search/contract.go",
    "api/internal/handler/export.go",
    "api/internal/mcp/search.go",
    "api/graph/resolver/schema.resolvers.go"
  ],
  "tests": [
    "api/internal/search/contract_test.go",
    "api/internal/handler/contract_test.go",
    "api/internal/mcp/contract_test.go"
  ],
  "issues": [
    "kapow-4vy"
  ],
  "evidence": {
    "type": "test",
    "description": "Shared ContractCase test matrix (~20 cases) runs against all three entry points. Each adapter translates entry-point-specific request/response formats but delegates to the same search.ValidateRequest function.",
    "references": [
      "api/internal/search/contract.go"
    ]
  },
  "created": "2026-03-10",
  "updated": "2026-03-10"
}

package search

import "encoding/json"

// ContractCase defines a single validation contract test case.
// The shared matrix is consumed by per-package test runners in search,
// handler, and mcp to prove equivalent requests produce equivalent
// validation outcomes across all entry points.
type ContractCase struct {
	Name          string        // Human-readable test name
	Request       SearchRequest // The search request to validate
	Authenticated bool          // Whether the caller is authenticated

	// Expected outcome.
	WantValid    bool   // true = expect 0 validation errors
	WantField    string // if invalid: expected error field
	WantContains string // if invalid: substring in error message

	// Entry-point applicability.
	SkipExport bool // true if this case doesn't apply to CSV export
	SkipMCP    bool // true if this case doesn't apply to MCP

	// Registry override. Nil means use NewRegistry().
	Registry *Registry
}

// ContractCases returns the shared validation contract test matrix.
func ContractCases() []ContractCase {
	restrictedReg := NewRegistryFromFields([]Field{
		NewTestSingleEnumField("secret_field", SearchabilityRestricted, []EnumOption{
			{Value: "a", Label: "A"},
			{Value: "b", Label: "B"},
		}),
	})

	return []ContractCase{
		// ── Valid filters ────────────────────────────────────────────
		{
			Name: "valid multi-enum filter",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "state", Value: json.RawMessage(`{"values":["CA"]}`)},
				},
			},
			Authenticated: true,
			WantValid:     true,
		},
		{
			Name: "valid numeric range filter",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "enrollment", Value: json.RawMessage(`{"min":1000,"max":50000}`)},
				},
			},
			Authenticated: true,
			WantValid:     true,
		},
		{
			Name: "valid full-text filter",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "name", Value: json.RawMessage(`{"query":"MIT"}`)},
				},
			},
			Authenticated: true,
			WantValid:     true,
		},

		// ── Invalid filters ─────────────────────────────────────────
		{
			Name: "unknown field",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "bogus", Value: json.RawMessage(`"x"`)},
				},
			},
			Authenticated: true,
			WantField:     "bogus",
			WantContains:  "unknown field",
		},
		{
			Name: "bad enum value",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "state", Value: json.RawMessage(`{"values":["XX"]}`)},
				},
			},
			Authenticated: true,
			WantField:     "state",
			WantContains:  "not in allowed options",
		},
		{
			Name: "empty multi-enum values",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "application_platforms", Value: json.RawMessage(`{"values":[]}`)},
				},
			},
			Authenticated: true,
			WantField:     "application_platforms",
			WantContains:  "at least one value required",
		},
		{
			Name: "numeric range both nil",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "enrollment", Value: json.RawMessage(`{}`)},
				},
			},
			Authenticated: true,
			WantField:     "enrollment",
			WantContains:  "at least one of min or max",
		},
		{
			Name: "numeric range out of bounds",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "admission_rate", Value: json.RawMessage(`{"min":-1}`)},
				},
			},
			Authenticated: true,
			WantField:     "admission_rate",
			WantContains:  "value out of allowed range",
		},

		// ── Auth sensitivity ────────────────────────────────────────
		{
			Name: "restricted field anonymous",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "secret_field", Value: json.RawMessage(`{"value":"a"}`)},
				},
			},
			Authenticated: false,
			WantField:     "secret_field",
			WantContains:  "authentication",
			Registry:      restrictedReg,
		},
		{
			Name: "restricted field authenticated",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "secret_field", Value: json.RawMessage(`{"value":"a"}`)},
				},
			},
			Authenticated: true,
			WantValid:     true,
			Registry:      restrictedReg,
		},

		// ── Sort ────────────────────────────────────────────────────
		{
			Name: "sort distance without location",
			Request: SearchRequest{
				Sort: &SortInput{Field: "distance", Direction: SortDirectionAsc},
			},
			Authenticated: true,
			WantField:     "_sort",
			WantContains:  "requires userLocation",
			SkipMCP:       true, // MCP does not pass sort
		},
		{
			Name: "sort blend_score without blend",
			Request: SearchRequest{
				Sort: &SortInput{Field: "blend_score", Direction: SortDirectionAsc},
			},
			Authenticated: true,
			WantField:     "_sort",
			WantContains:  "requires an active ranking blend",
			SkipMCP:       true,
		},
		{
			Name: "sort by name is valid",
			Request: SearchRequest{
				Sort: &SortInput{Field: "name", Direction: SortDirectionAsc},
			},
			Authenticated: true,
			WantValid:     true,
			SkipMCP:       true,
		},
		{
			Name: "sort unknown field",
			Request: SearchRequest{
				Sort: &SortInput{Field: "bogus_field", Direction: SortDirectionAsc},
			},
			Authenticated: true,
			WantField:     "_sort",
			WantContains:  "unknown sort field",
			SkipMCP:       true,
		},

		// ── Location ────────────────────────────────────────────────
		// MCP searchInput does not support UserLocation, so these are skipped.
		{
			Name: "valid user location",
			Request: SearchRequest{
				UserLocation: &UserLocation{Latitude: 42.0, Longitude: -72.0, State: "MA"},
			},
			Authenticated: true,
			WantValid:     true,
			SkipMCP:       true,
		},
		{
			Name: "invalid latitude",
			Request: SearchRequest{
				UserLocation: &UserLocation{Latitude: 91.0, Longitude: -72.0},
			},
			Authenticated: true,
			WantField:     "_userLocation",
			WantContains:  "latitude",
			SkipMCP:       true,
		},
		{
			Name: "invalid state code",
			Request: SearchRequest{
				UserLocation: &UserLocation{Latitude: 42.0, Longitude: -72.0, State: "m"},
			},
			Authenticated: true,
			WantField:     "_userLocation",
			WantContains:  "2-letter uppercase",
			SkipMCP:       true,
		},

		// ── Pagination ──────────────────────────────────────────────
		{
			Name: "limit exceeds max",
			Request: SearchRequest{
				Limit: 9999,
			},
			Authenticated: true,
			WantField:     "_limit",
			WantContains:  "limit exceeds",
			SkipExport:    true, // export overrides limit to maxRows
		},
		{
			Name: "negative offset",
			Request: SearchRequest{
				Offset: -1,
			},
			Authenticated: true,
			WantField:     "_offset",
			WantContains:  "offset must be non-negative",
			SkipExport:    true, // export has no offset
		},

		// ── Geo filters ─────────────────────────────────────────────
		{
			Name: "valid geo radius filter",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "location", Value: json.RawMessage(`{"kind":"radius","radius":{"lat":42.0,"lng":-72.0,"radius_km":50}}`)},
				},
			},
			Authenticated: true,
			WantValid:     true,
		},
		{
			Name: "geo radius exceeds max",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "location", Value: json.RawMessage(`{"kind":"radius","radius":{"lat":42.0,"lng":-72.0,"radius_km":9999}}`)},
				},
			},
			Authenticated: true,
			WantField:     "location",
			WantContains:  "exceeds maximum",
		},
		{
			Name: "geo radius not positive",
			Request: SearchRequest{
				Filters: []FilterInput{
					{Field: "location", Value: json.RawMessage(`{"kind":"radius","radius":{"lat":42.0,"lng":-72.0,"radius_km":0}}`)},
				},
			},
			Authenticated: true,
			WantField:     "location",
			WantContains:  "radius must be positive",
		},
	}
}

package router

import (
	"io/fs"
	"log/slog"
	"net"
	"net/http"
	"sync/atomic"
	"time"

	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/extension"
	"github.com/99designs/gqlgen/graphql/handler/transport"
	"github.com/99designs/gqlgen/graphql/playground"
	"github.com/go-chi/chi/v5"
	chimiddleware "github.com/go-chi/chi/v5/middleware"
	"github.com/go-chi/httprate"
	"github.com/jackc/pgx/v5/pgxpool"

	"github.com/ketang/kapow/api/graph/generated"
	"github.com/ketang/kapow/api/graph/resolver"
	"github.com/ketang/kapow/api/internal/auth"
	"github.com/ketang/kapow/api/internal/config"
	kapowhandler "github.com/ketang/kapow/api/internal/handler"
	kapowmcp "github.com/ketang/kapow/api/internal/mcp"
	kapowmiddleware "github.com/ketang/kapow/api/internal/middleware"
	kapowotel "github.com/ketang/kapow/api/internal/otel"
	"github.com/ketang/kapow/api/internal/preference"
	"github.com/ketang/kapow/api/internal/search"
	"github.com/ketang/kapow/api/internal/user"
)

// Deps holds the dependencies needed to construct the router.
type Deps struct {
	Config            *config.Config
	DB                *pgxpool.Pool
	Validator         auth.Validator
	Search            *search.Registry
	UserService       *user.Service
	PreferenceService *preference.Service

	// HTTPDetailConfig holds the hot-reloadable HTTP debug logging config.
	// A future admin endpoint can call .Store() to change settings at runtime.
	// If nil, New() initialises it from Config.
	HTTPDetailConfig *atomic.Pointer[kapowmiddleware.HTTPDetailConfig]

	// PrivateCIDRs restricts /private/* routes to these IP ranges.
	PrivateCIDRs []*net.IPNet

	// UI holds the embedded SPA filesystem. When non-nil, unmatched routes
	// serve the SPA (static files + index.html fallback).
	UI fs.FS
}

// New constructs the chi router with all middleware, routes, and handlers.
func New(deps Deps) http.Handler {
	r := chi.NewRouter()

	// Initialise hot-reloadable HTTP detail config if not provided.
	if deps.HTTPDetailConfig == nil {
		deps.HTTPDetailConfig = &atomic.Pointer[kapowmiddleware.HTTPDetailConfig]{}
		deps.HTTPDetailConfig.Store(kapowmiddleware.NewHTTPDetailConfig(deps.Config))
	}

	// Global middleware (applied to every request)
	if deps.Config.OTelEnabled {
		r.Use(kapowotel.Middleware("kapow-api"))
	}
	r.Use(kapowmiddleware.RequestID)
	r.Use(kapowmiddleware.Logging)
	r.Use(kapowmiddleware.Recovery)
	r.Use(kapowmiddleware.HTTPDetail(deps.HTTPDetailConfig))
	r.Use(chimiddleware.RealIP)
	r.Use(chimiddleware.StripSlashes)

	// Build gqlgen server
	gqlSrv := handler.New(generated.NewExecutableSchema(generated.Config{
		Resolvers: &resolver.Resolver{DB: deps.DB, Search: deps.Search, Preference: deps.PreferenceService},
	}))
	gqlSrv.AddTransport(transport.POST{})
	gqlSrv.AddTransport(transport.GET{})
	if deps.Config.GraphQLIntrospection {
		gqlSrv.Use(extension.Introspection{})
	}

	// GraphQL endpoint — optional auth (anonymous allowed, user provisioned if token present)
	r.Route("/graphql", func(r chi.Router) {
		r.Use(kapowmiddleware.OptionalAuth(deps.Validator))
		r.Use(kapowmiddleware.EnsureUser(deps.UserService))
		if deps.Config.RateLimitEnabled {
			r.Use(authRateLimitOverride(deps.Config.RateLimitGraphQLAuth))
			r.Use(httprate.Limit(
				deps.Config.RateLimitGraphQL,
				time.Minute,
				httprate.WithKeyFuncs(authOrIPKeyFunc),
			))
		}
		r.Post("/", gqlSrv.ServeHTTP)
		r.Get("/", gqlSrv.ServeHTTP)
	})

	// Dev-only mock auth endpoint — issues JWTs without Supabase
	if deps.Config.Env == "development" {
		r.Post("/dev/auth/login", kapowhandler.DevLogin(deps.Config.JWTSecret))
		slog.Info("router: dev auth endpoint enabled at /dev/auth/login")
	}

	// GraphQL Playground (dev only)
	if deps.Config.GraphQLPlayground {
		r.Get("/playground", playground.Handler("Kapow API", "/graphql"))
		slog.Info("router: GraphQL Playground enabled at /playground")
	}

	// CSV export endpoint — optional auth + rate limited
	r.Route("/api/export", func(r chi.Router) {
		r.Use(kapowmiddleware.OptionalAuth(deps.Validator))
		r.Use(kapowmiddleware.EnsureUser(deps.UserService))
		if deps.Config.RateLimitEnabled {
			r.Use(httprate.Limit(
				deps.Config.RateLimitExport,
				time.Minute,
				httprate.WithKeyFuncs(authOrIPKeyFunc),
			))
		}
		r.Get("/csv", kapowhandler.ExportCSV(deps.DB, deps.Search, deps.Config.MaxExportRows))
	})

	// Private (internal) routes — IP allowlisted
	r.Route("/private", func(r chi.Router) {
		if len(deps.PrivateCIDRs) > 0 {
			r.Use(kapowmiddleware.IPAllowlist(deps.PrivateCIDRs))
		}
		r.Get("/healthcheck", kapowhandler.Health(deps.DB))
		r.Get("/log-config", kapowhandler.LogConfig(deps.Config))
		r.Put("/log-config", kapowhandler.LogConfig(deps.Config))
	})

	// MCP (Model Context Protocol) endpoint — AI client integration
	// Protected with mandatory Auth middleware; unauthenticated requests
	// receive 401 with WWW-Authenticate header per MCP OAuth 2.1 spec.
	if deps.Config.MCPEnabled {
		r.Route("/mcp", func(r chi.Router) {
			r.Use(kapowmiddleware.Auth(deps.Validator))
			if deps.Config.RateLimitEnabled {
				r.Use(httprate.Limit(
					deps.Config.RateLimitMCP,
					time.Minute,
					httprate.WithKeyFuncs(authOrIPKeyFunc),
				))
			}
			r.Handle("/*", kapowmcp.NewHandler(deps.DB, deps.Search))
		})
		slog.Info("router: MCP endpoint enabled at /mcp")
	}

	// OAuth 2.1 Protected Resource Metadata (RFC 9728)
	r.Get("/.well-known/oauth-protected-resource", kapowhandler.ProtectedResourceMetadata(deps.Config))

	// Embedded SPA — serve static files and fall back to index.html
	if deps.UI != nil {
		r.NotFound(kapowhandler.SPAHandler(deps.UI).ServeHTTP)
		slog.Info("router: embedded SPA enabled")
	}

	slog.Info("router: initialized",
		"graphql_introspection", deps.Config.GraphQLIntrospection,
		"graphql_playground", deps.Config.GraphQLPlayground,
		"mcp_enabled", deps.Config.MCPEnabled,
		"rate_limit_enabled", deps.Config.RateLimitEnabled,
		"embedded_ui", deps.UI != nil,
	)

	return r
}

// authOrIPKeyFunc keys by user subject if authenticated, otherwise by client IP.
func authOrIPKeyFunc(r *http.Request) (string, error) {
	if claims := auth.GetClaims(r.Context()); claims != nil {
		return "user:" + claims.Subject, nil
	}
	return "ip:" + r.RemoteAddr, nil
}

// authRateLimitOverride returns middleware that raises the httprate request limit
// for authenticated users by setting WithRequestLimit in the request context.
func authRateLimitOverride(authLimit int) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			if auth.GetClaims(r.Context()) != nil {
				r = r.WithContext(httprate.WithRequestLimit(r.Context(), authLimit))
			}
			next.ServeHTTP(w, r)
		})
	}
}

package config

import (
	"fmt"
	"log/slog"
	"strings"
	"time"

	"github.com/caarlos0/env/v11"
)

// Config holds all application configuration loaded from environment variables.
type Config struct {
	Host string `env:"HOST" envDefault:"0.0.0.0"`
	Port int    `env:"PORT" envDefault:"8081"`

	DatabaseURL string `env:"DATABASE_URL,required"`

	JWTSecret    string `env:"JWT_SECRET"` //nolint:gosec // G117: config field name, not a hardcoded secret
	JWTPublicKey string `env:"JWT_PUBLIC_KEY"`
	JWTIssuer    string `env:"JWT_ISSUER"`
	JWTAudience  string `env:"JWT_AUDIENCE"`

	OIDCDiscoveryURL string `env:"OIDC_DISCOVERY_URL"`

	LogLevel  string `env:"LOG_LEVEL" envDefault:"info"`
	LogFormat string `env:"LOG_FORMAT" envDefault:"json"`

	Env string `env:"ENV" envDefault:"development"`

	CORSOrigins string `env:"CORS_ORIGINS"`

	GraphQLPlayground    bool `env:"GRAPHQL_PLAYGROUND" envDefault:"false"`
	GraphQLIntrospection bool `env:"GRAPHQL_INTROSPECTION" envDefault:"true"`

	MCPEnabled  bool `env:"MCP_ENABLED" envDefault:"true"`
	OTelEnabled bool `env:"OTEL_ENABLED" envDefault:"false"`

	ShutdownTimeout time.Duration `env:"SHUTDOWN_TIMEOUT" envDefault:"15s"`

	MaxExportRows int `env:"MAX_EXPORT_ROWS" envDefault:"500"`

	// Rate limiting
	RateLimitEnabled     bool   `env:"RATE_LIMIT_ENABLED" envDefault:"true"`
	RateLimitGraphQL     int    `env:"RATE_LIMIT_GRAPHQL" envDefault:"60"`
	RateLimitGraphQLAuth int    `env:"RATE_LIMIT_GRAPHQL_AUTH" envDefault:"120"`
	RateLimitExport      int    `env:"RATE_LIMIT_EXPORT" envDefault:"10"`
	RateLimitMCP         int    `env:"RATE_LIMIT_MCP" envDefault:"120"`
	PrivateAllowlistCIDRs string `env:"PRIVATE_ALLOWLIST_CIDRS" envDefault:"127.0.0.0/8,::1/128"`

	// HTTP debug logging
	HTTPDebugRequestHeaders  string `env:"HTTP_DEBUG_REQUEST_HEADERS" envDefault:"none"`
	HTTPDebugSelectedHeaders string `env:"HTTP_DEBUG_SELECTED_HEADERS" envDefault:"Content-Type,Accept,User-Agent"`
	HTTPDebugRedactSensitive bool   `env:"HTTP_DEBUG_REDACT_SENSITIVE" envDefault:"true"`
	HTTPDebugResponseMode    string `env:"HTTP_DEBUG_RESPONSE_MODE" envDefault:"none"`
	HTTPDebugBodyMaxBytes    int    `env:"HTTP_DEBUG_BODY_MAX_BYTES" envDefault:"4096"`

	// logLevelVar holds the dynamic log level. It is initialized by LogHandler
	// and can be updated at runtime to change the global log level without a restart.
	logLevelVar slog.LevelVar

	// swappableWriter is the log output target, swappable at runtime.
	swappableWriter *SwappableWriter

	// categoryHandler wraps the slog handler with per-category level overrides.
	categoryHandler *CategoryHandler
}

// Load parses and validates configuration from environment variables.
func Load() (*Config, error) {
	cfg := &Config{}
	if err := env.Parse(cfg); err != nil {
		return nil, fmt.Errorf("config: %w", err)
	}
	return cfg, nil
}

// Addr returns the host:port bind address.
func (c *Config) Addr() string {
	return fmt.Sprintf("%s:%d", c.Host, c.Port)
}

// LevelTrace is a custom log level below DEBUG for very detailed diagnostic
// output. Usage: logger.Log(ctx, config.LevelTrace, "msg", "key", val)
const LevelTrace = slog.Level(-8)

// ParseLogLevel converts a log level string to the corresponding slog.Level.
func ParseLogLevel(s string) slog.Level {
	switch s {
	case "trace":
		return LevelTrace
	case "debug":
		return slog.LevelDebug
	case "warn":
		return slog.LevelWarn
	case "error":
		return slog.LevelError
	default:
		return slog.LevelInfo
	}
}

// LogHandler returns an slog.Handler configured per LOG_LEVEL and LOG_FORMAT.
// The handler uses a dynamic LevelVar so the log level can be changed at
// runtime via LogLevelVar().Set() without recreating the handler. Output is
// routed through a SwappableWriter and wrapped with a CategoryHandler for
// per-category level overrides.
func (c *Config) LogHandler() slog.Handler {
	c.logLevelVar.Set(ParseLogLevel(c.LogLevel))
	c.swappableWriter = NewSwappableWriter()

	opts := &slog.HandlerOptions{
		Level:     &c.logLevelVar,
		AddSource: c.Env == "development",
		ReplaceAttr: func(groups []string, a slog.Attr) slog.Attr {
			if a.Key == slog.LevelKey {
				if level, ok := a.Value.Any().(slog.Level); ok && level == LevelTrace {
					a.Value = slog.StringValue("TRACE")
				}
			}
			return a
		},
	}

	var inner slog.Handler
	if c.LogFormat == "text" {
		inner = slog.NewTextHandler(c.swappableWriter, opts)
	} else {
		inner = slog.NewJSONHandler(c.swappableWriter, opts)
	}

	c.categoryHandler = NewCategoryHandler(inner, &c.logLevelVar)
	return c.categoryHandler
}

// LogLevelVar returns the dynamic log level variable. Callers can change
// the active log level at runtime by calling Set() on the returned LevelVar.
func (c *Config) LogLevelVar() *slog.LevelVar {
	return &c.logLevelVar
}

// LogWriter returns the swappable writer used for log output.
// Returns nil if LogHandler has not been called yet.
func (c *Config) LogWriter() *SwappableWriter {
	return c.swappableWriter
}

// LogCategoryHandler returns the category handler for per-category level overrides.
// Returns nil if LogHandler has not been called yet.
func (c *Config) LogCategoryHandler() *CategoryHandler {
	return c.categoryHandler
}

// HTTPDebugEnabled reports whether any HTTP debug logging is configured.
func (c *Config) HTTPDebugEnabled() bool {
	return c.HTTPDebugRequestHeaders != "none" || c.HTTPDebugResponseMode != "none"
}

// ParsedSelectedHeaders splits the comma-separated HTTPDebugSelectedHeaders
// into a trimmed slice of header names.
func (c *Config) ParsedSelectedHeaders() []string {
	raw := strings.Split(c.HTTPDebugSelectedHeaders, ",")
	out := make([]string, 0, len(raw))
	for _, h := range raw {
		h = strings.TrimSpace(h)
		if h != "" {
			out = append(out, h)
		}
	}
	return out
}

package main

import (
	"context"
	"log/slog"
	"os"
	"os/signal"
	"syscall"

	"github.com/golang-jwt/jwt/v5"
	"github.com/joho/godotenv"

	"github.com/ketang/kapow/api/internal/auth"
	"github.com/ketang/kapow/api/internal/config"
	"github.com/ketang/kapow/api/internal/db"
	kapowmiddleware "github.com/ketang/kapow/api/internal/middleware"
	kapowotel "github.com/ketang/kapow/api/internal/otel"
	"github.com/ketang/kapow/api/internal/preference"
	"github.com/ketang/kapow/api/internal/router"
	"github.com/ketang/kapow/api/internal/search"
	"github.com/ketang/kapow/api/internal/server"
	"github.com/ketang/kapow/api/internal/user"
	"github.com/ketang/kapow/api/internal/version"
	"github.com/ketang/kapow/api/ui"
)

func main() {
	// 1. Load .env (no-op if file is absent — dev only)
	_ = godotenv.Load()

	// 2. Parse and validate configuration
	cfg, err := config.Load()
	if err != nil {
		slog.Error("failed to load config", "error", err)
		os.Exit(1)
	}

	// 3. Configure structured logger
	slog.SetDefault(slog.New(cfg.LogHandler()))
	slog.Info("starting kapow api", "version", version.Version, "build_time", version.BuildTime, "env", cfg.Env)

	// 4. Initialize OpenTelemetry (opt-in via OTEL_ENABLED)
	ctx := context.Background()
	mp, tp, err := kapowotel.Init(ctx, kapowotel.Config{
		Enabled:     cfg.OTelEnabled,
		ServiceName: "kapow-api",
		Version:     version.Version,
		Environment: cfg.Env,
	})
	if err != nil {
		slog.Error("failed to initialize OpenTelemetry", "error", err)
		os.Exit(1)
	}
	defer func() {
		if err := kapowotel.Shutdown(ctx, mp, tp); err != nil {
			slog.Error("otel shutdown error", "error", err)
		}
	}()
	if cfg.OTelEnabled {
		slog.Info("otel: initialized", "service", "kapow-api")
	}

	// 5. Connect to database
	pool, err := db.Connect(ctx, cfg.DatabaseURL)
	if err != nil {
		slog.Error("failed to connect to database", "error", err)
		os.Exit(1) //nolint:gocritic // fatal startup error; OS reclaims resources
	}
	defer pool.Close()

	// 6. Select JWT validator
	var jwtOpts []jwt.ParserOption
	if cfg.JWTIssuer != "" {
		jwtOpts = append(jwtOpts, jwt.WithIssuer(cfg.JWTIssuer))
	}
	if cfg.JWTAudience != "" {
		jwtOpts = append(jwtOpts, jwt.WithAudience(cfg.JWTAudience))
	}

	var validator auth.Validator
	if cfg.JWTPublicKey != "" {
		validator, err = auth.NewRSAValidator(cfg.JWTPublicKey, jwtOpts...)
		if err != nil {
			slog.Error("failed to create RSA JWT validator", "error", err)
			os.Exit(1) //nolint:gocritic // fatal startup error; OS reclaims resources
		}
		slog.Info("auth: using RS256 JWT validator")
	} else {
		validator, err = auth.NewHMACValidator(cfg.JWTSecret, jwtOpts...)
		if err != nil {
			slog.Error("failed to create HMAC JWT validator — set JWT_PUBLIC_KEY or JWT_SECRET", "error", err)
			os.Exit(1) //nolint:gocritic // fatal startup error; OS reclaims resources
		}
		slog.Info("auth: using HS256 JWT validator")
	}

	// 7. Parse private endpoint CIDR allowlist
	privateCIDRs, err := kapowmiddleware.ParseCIDRs(cfg.PrivateAllowlistCIDRs)
	if err != nil {
		slog.Error("failed to parse PRIVATE_ALLOWLIST_CIDRS", "error", err)
		os.Exit(1) //nolint:gocritic // fatal startup error; OS reclaims resources
	}
	slog.Info("private endpoint allowlist configured", "cidrs", cfg.PrivateAllowlistCIDRs)

	// 8. Build router
	userSvc := user.NewService(pool)
	prefSvc := preference.NewService(pool)

	// Resolve embedded UI assets (nil when built without -tags ui).
	uiFS := ui.Assets()
	if uiFS != nil {
		slog.Info("embedded UI assets loaded")
	}

	r := router.New(router.Deps{
		Config:            cfg,
		DB:                pool,
		Validator:         validator,
		Search:            search.NewRegistry(),
		UserService:       userSvc,
		PreferenceService: prefSvc,
		PrivateCIDRs:      privateCIDRs,
		UI:                uiFS,
	})

	// 9. Build HTTP server
	srv := server.New(cfg, r)

	// 10. Listen for OS signals
	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	// 11. Start server in background goroutine
	go func() {
		slog.Info("server: listening", "addr", cfg.Addr())
		if err := srv.ListenAndServe(); err != nil {
			// ErrServerClosed is expected during graceful shutdown
			slog.Info("server: stopped", "reason", err)
		}
	}()

	// 12. Block until signal received
	sig := <-sigCh
	slog.Info("signal received", "signal", sig)

	// 13. Graceful shutdown
	if err := server.Shutdown(srv, cfg.ShutdownTimeout); err != nil {
		slog.Error("server: shutdown error", "error", err)
		os.Exit(1)
	}
}

