python3 -c "
import json, sys

schema = json.load(open('contracts/schema/technical-contract.schema.json'))
data = json.load(open('contracts/technical-contracts.json'))

# Basic validation without jsonschema library
required = schema['required']
valid_statuses = schema['properties']['status']['enum']
valid_categories = schema['properties']['category']['enum']
id_pattern = schema['properties']['id']['pattern']

import re
errors = []
for i, entry in enumerate(data):
    for field in required:
        if field not in entry:
            errors.append(f'Entry {i}: missing required field \"{field}\"')
    if entry.get('status') not in valid_statuses:
        errors.append(f'Entry {i}: invalid status \"{entry.get(\"status\")}\"')
    if entry.get('category') not in valid_categories:
        errors.append(f'Entry {i}: invalid category \"{entry.get(\"category\")}\"')
    if not re.match(schema['properties']['id']['pattern'], entry.get('id', '')):
        errors.append(f'Entry {i}: id does not match pattern')
    # Check evidence type
    if 'evidence' in entry:
        ev_types = schema['properties']['evidence']['properties']['type']['enum']
        if entry['evidence'].get('type') not in ev_types:
            errors.append(f'Entry {i}: invalid evidence type')

if errors:
    for e in errors:
        print(f'ERROR: {e}', file=sys.stderr)
    sys.exit(1)
else:
    print(f'Valid: {len(data)} contract entries, all pass schema checks')
    for entry in data:
        print(f'  - {entry[\"id\"]} [{entry[\"status\"]}] ({entry[\"category\"]})')
"

